import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { useT } from '../context/LanguageContext';
import './Profile.css';

function InfoRow({ label, value, arabic }) {
  if (!value) return null;
  return (
    <div className="info-row">
      <span className="info-label">{label}</span>
      <span className={`info-value ${arabic ? 'arabic' : ''}`}>{value}</span>
    </div>
  );
}

function Section({ title, children }) {
  return (
    <div className="profile-section card">
      <h3 className="section-heading">{title}</h3>
      <div className="section-body">{children}</div>
    </div>
  );
}

export default function Profile() {
  const { auth, apiHeaders } = useAuth();
  const t = useT();
  const [individu, setIndividu] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!auth?.uuid) return;
    axios.get(`/api/student/individu/${auth.uuid}`, { headers: apiHeaders })
      .then(r => setIndividu(r.data))
      .catch(() => setError(t.profile.errorLoad))
      .finally(() => setLoading(false));
  }, [auth, apiHeaders]); // eslint-disable-line

  if (loading) return <div className="page-loader"><div className="spinner" /></div>;
  if (error) return <div className="error-banner">{error}</div>;

  return (
    <div className="profile-page">
      <div className="page-header">
        <div>
          <h1>{t.profile.title}</h1>
          <p className="page-subtitle">{t.profile.subtitle}</p>
        </div>
      </div>

      {individu && (
        <>
          <div className="profile-hero card">
            <div className="profile-avatar-lg">
              {(individu.prenomLatin?.[0] || 'E').toUpperCase()}
            </div>
            <div className="profile-hero-info">
              <h2>{individu.prenomLatin} {individu.nomLatin}</h2>
              <p className="arabic-name">{individu.prenomArabe} {individu.nomArabe}</p>
              <p className="profile-id">{t.profile.identifiant} : {individu.identifiant || auth.username}</p>
            </div>
          </div>

          <Section title={t.profile.frenchSection}>
            <InfoRow label={t.profile.nom}           value={individu.nomLatin} />
            <InfoRow label={t.profile.prenom}        value={individu.prenomLatin} />
            <InfoRow label={t.profile.dateNaissance} value={individu.dateNaissance} />
            <InfoRow label={t.profile.lieuNaissance} value={individu.lieuNaissance} />
            <InfoRow label={t.profile.email}         value={individu.email} />
          </Section>

          <Section title={t.profile.arabicSection}>
            <InfoRow label={t.profile.arabicNom}   value={individu.nomArabe}          arabic />
            <InfoRow label={t.profile.arabicPrenom} value={individu.prenomArabe}       arabic />
            <InfoRow label={t.profile.arabicLieu}   value={individu.lieuNaissanceArabe} arabic />
          </Section>
        </>
      )}
    </div>
  );
}
